## Testing your implementation

These examples demonstrate how to test your implementation when using Group within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the Group component renders correctly with children

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Group, Button, NimbusProvider } from "@commercetools/nimbus";

describe("Group - Basic rendering", () => {
  it("renders group with children", () => {
    render(
      <NimbusProvider>
        <Group aria-label="Test group">
          <Button>First</Button>
          <Button>Second</Button>
          <Button>Third</Button>
        </Group>
      </NimbusProvider>
    );

    const group = screen.getByRole("group", { name: "Test group" });
    expect(group).toBeInTheDocument();

    // Verify all children are rendered
    expect(screen.getByRole("button", { name: "First" })).toBeInTheDocument();
    expect(screen.getByRole("button", { name: "Second" })).toBeInTheDocument();
    expect(screen.getByRole("button", { name: "Third" })).toBeInTheDocument();
  });

  it("applies custom className and id", () => {
    render(
      <NimbusProvider>
        <Group
          aria-label="Custom group"
          className="custom-class"
          id="custom-id"
        >
          <Button>Content</Button>
        </Group>
      </NimbusProvider>
    );

    const group = screen.getByRole("group", { name: "Custom group" });
    expect(group).toHaveClass("custom-class");
    expect(group).toHaveAttribute("id", "custom-id");
  });
});
```

